    """Call a function value (builtin or UserFunction) with evaluated args."""
    if callable(func) and not isinstance(func, UserFunction):
        return func(*args)
    if isinstance(func, UserFunction):
        call_env = Environment(parent=func.closure_env)
        for param, arg in zip(func.params, args):
